# Неудобные промышленные объекты: (lat, lon, radius_km, penalty, name)
# penalty — сколько вычитается из итоговой оценки при попадании в радиус
# Sources: Aquanet, Veolia, ZZO, Wikipedia PL, OSM
_NUISANCE_SITES = [
    (52.430,  16.990,  4.0, 1.5, "ITPOK Spalarnia"),
    (52.436,  16.988,  5.0, 1.0, "EC Karolin (Veolia)"),
    (52.431,  16.959,  2.5, 1.2, "Oczyszczalnia LOŚ Serbska (Aquanet)"),
    (52.449,  16.981,  3.0, 1.5, "Oczyszczalnia COŚ Koziegłowy (Aquanet)"),
    (52.497,  16.888,  3.0, 1.2, "Składowisko ZZO Suchy Las"),
    (52.412,  17.031,  1.5, 0.8, "VW Antoninek (fabryka)"),
    (52.389,  16.887,  1.5, 0.8, "VW Odlewnia Wilda"),
    (52.328,  16.900,  3.0, 1.2, "Luvena SA Luboń (zakład chemiczny)"),
]

from math import radians, sin, cos, sqrt, atan2 as _atan2

def _haversine(lat1, lon1, lat2, lon2):
    R = 6371
    dl = radians(lat2 - lat1); do = radians(lon2 - lon1)
    a = sin(dl/2)**2 + cos(radians(lat1))*cos(radians(lat2))*sin(do/2)**2
    return R * 2 * _atan2(sqrt(a), sqrt(1 - a))

def _nuisance_penalty(lat, lon):
    """Total penalty for proximity to industrial/polluting sites (capped at 2.5)."""
    if lat is None or lon is None:
        return 0.0
    total = 0.0
    for slat, slon, radius, penalty, _ in _NUISANCE_SITES:
        dist = _haversine(lat, lon, slat, slon)
        if dist < radius:
            # linear: full penalty at 0, zero at radius boundary
            total += penalty * (1 - dist / radius)
    return round(min(2.5, total), 2)

def _noise_penalty(noise, floor=None):
    """
    noise: dict {source: max_ldwn_dba} from noise_cache.json (GEOPOZ 2017, facade level).
    Data is worst-case facade exposure; upper floors receive reduced penalty
    because noise attenuates with height.
    """
    if not noise:
        return 0.0
    max_ldwn = max(noise.values())
    if max_ldwn <= 60:
        return 0.0
    if max_ldwn <= 65:
        base = 0.1
    elif max_ldwn <= 70:
        base = 0.2
    else:
        base = 0.4
    try:
        fl = int(floor) if floor not in (None, "") else None
    except (ValueError, TypeError):
        fl = None
    mult = max(0.3, 1.0 - 0.1 * max(0, (fl or 1) - 2)) if fl else 1.0
    return round(base * mult, 3)

def _score_district(district, city):
    """Check district first, then city name."""
    if district and district in DISTRICT_SCORES:
        return float(DISTRICT_SCORES[district])
    if city and city in DISTRICT_SCORES:
        return float(DISTRICT_SCORES[city])
    return float(_DEFAULT_DISTRICT_SCORE)


def _score_price(price):
    # Filter from 500k; ≤700k scores 10 (ideal), above — decreasing
    if price is None:
        return 5.0  # neutral, not redistributed
    if price <= 700_000:
        return 10.0
    if price <= 900_000:
        return 10.0 - 3.0 * (price - 700_000) / 200_000   # 700k→10, 900k→7
    if price <= 1_200_000:
        return max(0.0, 7.0 - 7.0 * (price - 900_000) / 300_000)  # 900k→7, 1200k→0
    return 0.0


def _score_area(area):
    if area is None:
        return 5.0
    if area < 70 or area > 120:
        return 0.0
    if 85 <= area <= 105:
        return 10.0
    if area < 85:
        return 4.0 + 6.0 * (area - 70) / 15   # 70→4, 85→10
    return 10.0 - 3.0 * (area - 105) / 15      # 105→10, 120→7


def _score_rooms(rooms):
    if rooms is None:
        return 5.0  # neutral, not redistributed
    if rooms == 4:
        return 10.0
    if rooms == 5:
        return 8.0
    if rooms in (3, 6):
        return 7.0
    return 3.0  # ≤2 or 7+


def _score_transport(tp, tram_min, dist_center_min):
    # ≤5 мин → 10; каждая доп. минута −1 балл; <0 → 0
    m = tram_min if tram_min is not None else dist_center_min
    if m is None:
        return 5.0
    return max(0.0, 10.0 - max(0, m - 5))


def _score_type(tp):
    return 9.0


_BASE_W = {
    "district":  0.30,
    "transport": 0.20,
    "price":     0.15,
    "area":      0.20,
    "rooms":     0.15,
    "type":      0.00,
}


def compute_score(price, area, rooms, tp, dist_tram, dist_center, tram_min=None, dist_center_min=None, district=None, city=None, lat=None, lon=None, noise=None, floor=None):
    factors = [
        (_score_transport(tp, tram_min, dist_center_min), _BASE_W["transport"]),
        (_score_district(district, city),               _BASE_W["district"]),
        (_score_price(price),                           _BASE_W["price"]),
        (_score_area(area),                             _BASE_W["area"]),
        (_score_rooms(rooms),                           _BASE_W["rooms"]),
        (_score_type(tp),                               _BASE_W["type"]),
    ]
    total_w = sum(w for _, w in factors)
    base = sum(sc * w for sc, w in factors) / total_w
    penalty = _nuisance_penalty(lat, lon) + _noise_penalty(noise, floor)
    return round(max(0.0, base - penalty), 1)


def _f(v):
    try:
        return float(v) if v not in (None, "") else None
    except (ValueError, TypeError):
        return None


def _rooms(raw):
    if raw in (None, ""):
        return None
    if str(raw) == "7+":
        return 7
    try:
        return int(raw)
    except (ValueError, TypeError):
        return None


def score_from_csv(r):
    return compute_score(
        price=_f(r.get("price_zl")),
        area=_f(r.get("area_m2")),
        rooms=_rooms(r.get("rooms")),
        tp=r.get("type", ""),
        dist_tram=_f(r.get("drive_tram_km")) or _f(r.get("dist_tram")),
        dist_center=_f(r.get("drive_ratusz_km")) or _f(r.get("dist_km")),
        district=r.get("district", ""),
        city=r.get("city", ""),
    )


def score_from_jsrow(r):
    return compute_score(
        price=r.get("price"),
        area=r.get("area"),
        rooms=_rooms(r.get("rooms")),
        tp=r.get("type", ""),
        dist_tram=r.get("dist_tram"),
        dist_center=r.get("dist"),
        tram_min=r.get("tram_min"),
        dist_center_min=r.get("dist_min"),
        district=r.get("district", ""),
        city=r.get("city", ""),
        lat=r.get("lat"),
        lon=r.get("lon"),
        noise=r.get("noise"),
        floor=r.get("floor"),
    )
